# Self-extracting patch script generated to apply workspace changes on server
import base64
import io
import os
import zipfile

# Base64 encoded zip data containing all modified/new files
ZIP_DATA = """"""

# List of files to delete
DELETED_FILES = ['schema/curated_datamodels/tables/gsws/govt_emp_data.yaml', 'schema/curated_datamodels/tables/gsws/gsws_caste_religion_master.yaml', 'schema/curated_datamodels/tables/gsws/gsws_cluster_master.yaml', 'schema/curated_datamodels/tables/gsws/gsws_demographic_details.yaml', 'schema/curated_datamodels/tables/gsws/gsws_hh_sixstep_cal.yaml', 'schema/curated_datamodels/tables/gsws/gsws_hh_volunteer_mapping.yaml', 'schema/curated_datamodels/tables/gsws/gsws_relation_masters.yaml', 'schema/curated_datamodels/tables/gsws/gsws_revenue_village_map.yaml', 'schema/curated_datamodels/tables/gsws/gsws_sec_building_lat_longs.yaml', 'schema/curated_datamodels/tables/gsws/gsws_sec_secretariat_accdtls.yaml', 'schema/curated_datamodels/tables/gsws/gsws_sec_sim_mobile_details.yaml', 'schema/curated_datamodels/tables/gsws/gws_citizen_bank_dtls_tab.yaml', 'schema/curated_datamodels/tables/gsws/gws_cluster_map_tab.yaml', 'schema/curated_datamodels/tables/gsws/gws_constiuency_sec_master.yaml', 'schema/curated_datamodels/tables/gsws/gws_death_capture_tab.yaml', 'schema/curated_datamodels/tables/gsws/gws_district_master.yaml', 'schema/curated_datamodels/tables/gsws/gws_emp_hh_cap_geo_cor_tab.yaml', 'schema/curated_datamodels/tables/gsws/gws_hh_mem_data.yaml', 'schema/curated_datamodels/tables/gsws/gws_lgd_mdl_rev_master.yaml', 'schema/curated_datamodels/tables/gsws/gws_mauddata.yaml', 'schema/curated_datamodels/tables/gsws/secretariate_employee_details.yaml', 'schema/curated_datamodels/tables/misc/oracle_temp_data_nopkey_1_dummy.yaml', 'view_students.py']

def apply_patch():
    print("Starting patch application...")
    
    # 1. Delete files
    for rel_path in DELETED_FILES:
        if os.path.exists(rel_path):
            try:
                os.remove(rel_path)
                print(f"Deleted: {rel_path}")
            except Exception as e:
                print(f"Failed to delete {rel_path}: {e}")
        else:
            print(f"Already deleted / does not exist: {rel_path}")
            
    # 2. Extract zip containing modified files
    zip_bytes = base64.b64decode(ZIP_DATA)
    zip_buffer = io.BytesIO(zip_bytes)
    
    with zipfile.ZipFile(zip_buffer, "r") as zip_file:
        for file_info in zip_file.infolist():
            rel_path = file_info.filename
            
            # Ensure target directory exists
            target_dir = os.path.dirname(rel_path)
            if target_dir and not os.path.exists(target_dir):
                os.makedirs(target_dir, exist_ok=True)
                
            # Extract and write the file
            with zip_file.open(file_info) as source, open(rel_path, "wb") as target:
                target.write(source.read())
            print(f"Updated: {rel_path}")
            
    print("\nPatch applied successfully! All YAMLs, schema definitions, and agent code are synchronized.")
    print("Note: You may need to rebuild your database and vector indexes if schemas changed:")
    print("  python create_database.py / python create_schema.py (to compile database)")
    print("  python build_milvus_index.py / python pipeline.py --fewshots (to re-index in Milvus)")

if __name__ == "__main__":
    apply_patch()
